import { Component } from '@angular/core';
import { SlideOutService } from '../slide-out.service';

@Component({
  selector: 'app-slide-out-panel',
  templateUrl: './slide-out-panel.component.html',
  styleUrls: ['./slide-out-panel.component.css']
})
export class SlideOutPanelComponent {
  isOpen = false; // Define the isOpen property for this component

  constructor(private slideOutControlService: SlideOutControlService) {
    // Subscribe to the isOpen$ observable to update isOpen when the state changes
    this.slideOutControlService.isOpen$.subscribe((isOpen) => {
      this.isOpen = isOpen;
    });
  }

  // Other methods and logic specific to the SlideOutPanelComponent
}
